mapper.select:
select fq.id, fq.factory_id, factory.factory_name, fq.style_number, fq.category_id, fjc.category, fq.quotation, fq.image_path, fq.created_date, fq.flag from factory_quotation fq left join factory on fq.factory_id = factory.id and factory.flag = 0 left join factory_job_category fjc on fq.category_id = fjc.id and fjc.flag = 0 where fq.flag = #{flag}
and fq.factory_id = #{factoryId}
and fq.style_number like CONCAT('%', #{styleNumber}, '%')
and fq.category_id = #{categoryId}
order by factory.factory_name desc

select fq.id, fq.factory_id, fq.style_number, fq.category_id, fjc.category from factory_quotation fq left join factory on fq.factory_id = factory.id and factory.flag = 0 left join factory_job_category fjc on fq.category_id = fjc.id and fjc.flag = 0 where fq.flag = #{flag}
and fq.factory_id = #{factoryId}
order by fq.created_date desc
